from pathlib import Path

for path in Path('docs').glob('*.md'):
    text = path.read_text(encoding='utf-8')
    lines = text.splitlines()
    in_code = False
    complexity = []
    body = []
    for line in lines:
        if line.startswith('```'):
            in_code = not in_code
            body.append(line)
            continue
        if not in_code and ('时间复杂度' in line or '空间复杂度' in line):
            if line not in complexity:
                complexity.append(line)
            continue
        body.append(line)

    if complexity:
        # Insert complexity analysis after the last code fence.
        insert_at = None
        for idx in range(len(body) - 1, -1, -1):
            if body[idx].startswith('```'):
                insert_at = idx + 1
                break
        if insert_at is None:
            insert_at = len(body)

        trailer = ['','## 复杂度分析',''] + complexity
        body[insert_at:insert_at] = trailer
        new_text = '\n'.join(body) + '\n'
        if new_text != text:
            path.write_text(new_text, encoding='utf-8')
